import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Mock the module that exports `truncateContent`.
// Adjust the path to match the actual location of the function in the project.
vi.mock('../src/utils/truncateContent', () => ({
  truncateContent: vi.fn(),
}));

// Import the mocked function after mocking.
import { truncateContent } from '../src/utils/truncateContent';

describe('truncateContent', () => {
  beforeEach(() => {
    // Reset mock implementations before each test.
    (truncateContent as any).mockReset();
  });

  it('should handle happy path when content length is less than maxLength', () => {
    const content = 'Short text';
    const maxLength = 20;
    // Simulate realistic implementation: return content unchanged.
    (truncateContent as any).mockImplementation((c: string, m: number = 80) =>
      c.length <= m ? c : c.slice(0, m) + '...',
    );

    const result = truncateContent(content, maxLength);
    expect(result).toBe(content);
    expect(truncateContent).toHaveBeenCalledWith(content, maxLength);
  });

  it('should handle edge case when content length exceeds maxLength', () => {
    const content = 'This is a very long piece of text that definitely exceeds the limit.';
    const maxLength = 30;
    (truncateContent as any).mockImplementation((c: string, m: number = 80) =>
      c.length <= m ? c : c.slice(0, m) + '...',
    );

    const result = truncateContent(content, maxLength);
    expect(result).toBe(content.slice(0, maxLength) + '...');
    expect(result.length).toBe(maxLength + 3); // includes ellipsis
    expect(truncateContent).toHaveBeenCalledWith(content, maxLength);
  });

  it('should handle null/empty inputs gracefully', () => {
    // Define behavior for null, undefined, empty string, and zero maxLength.
    (truncateContent as any).mockImplementation((c: any, m: number = 80) => {
      if (c == null) return '';
      const str = String(c);
      return str.length <= m ? str : str.slice(0, m) + '...';
    });

    expect(truncateContent(null)).toBe('');
    expect(truncateContent(undefined)).toBe('');
    expect(truncateContent('')).toBe('');
    // When maxLength is 0, expect an empty string (no characters, no ellipsis).
    expect(truncateContent('non-empty', 0)).toBe('');
    expect(truncateContent).toHaveBeenCalledTimes(4);
  });
});

